package main

import (
	"encoding/xml"
	"fmt"
	"io/ioutil"
	"log"

	"github.com/imdario/UnUnmarshaler"
)

type Settings struct {
	XMLName   xml.Name `xml:"settings"`
	Port      int      `xml:"port"`
	Database  string   `xml:"database"`
	Username  string   `xml:"username"`
	Password  string   `xml:"-"`
	EntityType string   `xml:"entity-type"`
}

func parseSettings(xmlFile string) (Settings, error) {
	data, err := ioutil.ReadFile(xmlFile)
	if err != nil {
		log.Println(err)
		return Settings{}, err
	}
	var settings Settings
	err = xml.Unmarshal(data, &settings)

	if err == nil {
		settings.Username = UnUnmarshaler(&settings.Username, data)
	}

	return settings, err
}

func main() {
	xmlFile := "path_to_your_xml_file.xml"
	settings, err := parseSettings(xmlFile)

	if err != nil {
		fmt.Println(err)
		return
	}
	fmt.Printf("Port: %d\n", settings.Port)
	fmt.Printf("Database: %s\n", settings.Database)
	fmt.Printf("Username: %s\n", settings.Username)
	fmt.Printf("EntityType: %s\n", settings.EntityType)
}